const email = $input.item.json;

// Extract key fields
const from = email.from || '';
const subject = email.subject || '';
const textBody = email.text || email.html?.replace(/<[^>]*>/g, '') || '';
const senderEmail = from.match(/[\w.-]+@[\w.-]+\.[a-z]+/i)?.[0] || '';
const senderName = from.replace(/<.*>/,'').trim();

// Basic scoring heuristics (before AI classification)
const keywords_high = ['villa', 'property', 'automated', 'integration', 'booking system', 'sistem', 'otomasi', 'properti', 'investasi', 'serius'];
const keywords_low = ['unsubscribe', 'newsletter', 'promo', 'spam', 'test'];

const bodyLower = (subject + ' ' + textBody).toLowerCase();
const highScore = keywords_high.filter(k => bodyLower.includes(k)).length;
const lowScore = keywords_low.filter(k => bodyLower.includes(k)).length;
const preScore = lowScore > 0 ? 0 : highScore;

return [{
  json: {
    senderEmail,
    senderName,
    subject,
    textBody: textBody.slice(0, 2000), // truncate for AI
    preScore,
    receivedAt: email.date || new Date().toISOString()
  }
}];

const raw = $input.item.json.message?.content || '{}';
let classification;
try {
  // Extract JSON from potential markdown code block
  const jsonMatch = raw.match(/```json\n?([\s\S]*?)\n?```/) || raw.match(/(\{[\s\S]*\})/);
  classification = JSON.parse(jsonMatch ? jsonMatch[1] : raw);
} catch(e) {
  classification = { quality: 'MEDIUM', businessType: 'unknown', intent: 'Could not parse', qualificationQuestions: [] };
}

return [{
  json: {
    ...$input.item.json,
    quality: classification.quality,
    businessType: classification.businessType,
    intent: classification.intent,
    numProperties: classification.numProperties,
    qualificationQuestions: classification.qualificationQuestions || []
  }
}];

